CREATE OR REPLACE FUNCTION public.calculate_rpn()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.rpn := new.severity * new.occurrence * new.detection;
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.create_org_invitation_as(p_org uuid, p_email text, p_role app_role, p_actor uuid)
 RETURNS organization_invitations
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_allowed int;
  v_used int;
  v_now timestamptz := now();
  v_inv public.organization_invitations;
begin
  perform set_config('row_security', 'off', true);

  -- uprawnienia: actor musi być admin/champion
  if not exists (
    select 1
    from public.organization_members om
    where om.organization_id = p_org
      and om.user_id = p_actor
      and om.role in ('admin','champion')
  ) then
    raise exception 'Not allowed';
  end if;

  select ol.invites_allowed_total
    into v_allowed
  from public.organization_license ol
  where ol.organization_id = p_org
    and (ol.valid_from is null or ol.valid_from <= v_now::date)
    and (ol.valid_to   is null or ol.valid_to   >= v_now::date);

  if v_allowed is null then
    raise exception 'No active license for organization';
  end if;

  select count(*)
    into v_used
  from public.organization_invitations oi
  where oi.organization_id = p_org
    and oi.status in ('PENDING','ACTIVE');

  if v_used >= v_allowed then
    raise exception 'Invite limit reached (%/%).', v_used, v_allowed;
  end if;

  insert into public.organization_invitations (
    id, organization_id, email, role, token, status,
    invited_by, created_at, expires_at, accepted_at, accepted_by
  ) values (
    gen_random_uuid(), p_org, p_email, p_role, gen_random_uuid(), 'PENDING',
    p_actor, now(), now() + interval '7 days', null, null
  )
  returning * into v_inv;

  return v_inv;
end;
$function$

CREATE OR REPLACE FUNCTION public.create_process_revision_and_tag_changes(p_process_id uuid, p_change_description text, p_changed_pfd boolean DEFAULT false, p_changed_pfmea boolean DEFAULT false, p_changed_pcp boolean DEFAULT false, p_pfmea_row_ids uuid[] DEFAULT '{}'::uuid[], p_pcp_row_ids uuid[] DEFAULT '{}'::uuid[], p_pfd_node_ids uuid[] DEFAULT '{}'::uuid[], p_pfd_edge_ids uuid[] DEFAULT '{}'::uuid[])
 RETURNS TABLE(revision_id uuid, revision_label text, pfd_rev integer, pfmea_rev integer, pcp_rev integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_prev record;
  v_new_pfd integer;
  v_new_pfmea integer;
  v_new_pcp integer;
  v_new_rev_id uuid;
begin
  if p_change_description is null or length(trim(p_change_description)) = 0 then
    raise exception 'change_description is required';
  end if;

  -- uprawnienia (ważne)
  if not public.can_edit() then
    raise exception 'Not allowed';
  end if;

  select r.*
  into v_prev
  from public.projects pr
  left join public.process_revisions r on r.id = pr.current_revision_id
  where pr.id = p_process_id;

  if not found then
    raise exception 'Process not found: %', p_process_id;
  end if;

  v_new_pfd := coalesce(v_prev.pfd_rev, 1) + case when p_changed_pfd then 1 else 0 end;
  v_new_pfmea := coalesce(v_prev.pfmea_rev, 1) + case when p_changed_pfmea then 1 else 0 end;
  v_new_pcp := coalesce(v_prev.pcp_rev, 1) + case when p_changed_pcp then 1 else 0 end;

  insert into public.process_revisions (
    project_id,
    pfd_rev, pfmea_rev, pcp_rev,
    change_description,
    created_by
  )
  values (
    p_process_id,
    v_new_pfd, v_new_pfmea, v_new_pcp,
    p_change_description,
    auth.uid()
  )
  returning id into v_new_rev_id;

  update public.projects
  set
    current_revision_id = v_new_rev_id,
    updated_at = now(),
    updated_by = auth.uid()
  where id = p_process_id;

  if array_length(p_pfmea_row_ids, 1) is not null then
    update public.pfmea_rows
    set revision_id = v_new_rev_id
    where id = any(p_pfmea_row_ids);
  end if;

  if array_length(p_pcp_row_ids, 1) is not null then
    update public.control_plan_rows
    set revision_id = v_new_rev_id
    where id = any(p_pcp_row_ids);
  end if;

  if array_length(p_pfd_node_ids, 1) is not null then
    update public.pfd_nodes
    set revision_id = v_new_rev_id
    where id = any(p_pfd_node_ids);
  end if;

  if array_length(p_pfd_edge_ids, 1) is not null then
    update public.pfd_edges
    set revision_id = v_new_rev_id
    where id = any(p_pfd_edge_ids);
  end if;

  return query
  select
    v_new_rev_id,
    (v_new_pfd::text || '.' || v_new_pfmea::text || '.' || v_new_pcp::text) as revision_label,
    v_new_pfd, v_new_pfmea, v_new_pcp;
end;
$function$

CREATE OR REPLACE FUNCTION public.pfmea_calc_scores()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  -- CURRENT
  if new.severity is not null and new.occurrence is not null and new.detection is not null then
    new.rpn := new.severity * new.occurrence * new.detection;
    new.oxd := new.occurrence * new.detection;
  else
    new.rpn := null;
    new.oxd := null;
  end if;

  -- AFTER ACTIONS
  if new.severity2 is not null and new.occurrence2 is not null and new.detection2 is not null then
    new.rpn2 := new.severity2 * new.occurrence2 * new.detection2;
    new.oxd2 := new.occurrence2 * new.detection2;
  else
    new.rpn2 := null;
    new.oxd2 := null;
  end if;

  -- CURRENT = prefer AFTER ACTIONS
  new.rpn_current := coalesce(new.rpn2, new.rpn);
  new.oxd_current := coalesce(new.oxd2, new.oxd);

  return new;
end;
$function$

